-- Phase 10A: additive procurement, suppliers, and equipment foundation.
create table public.suppliers(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,owner_id uuid not null,legal_name text not null,trading_name text,supplier_type text not null check(supplier_type in('raw_material','fragrance','packaging','equipment','laboratory','compliance_service','logistics','printing','general','mixed')),status text not null default 'research' check(status in('research','candidate','approved_internal','active','paused','rejected','archived')),website_url text,country_code text,default_currency text,default_lead_time_days integer check(default_lead_time_days>=0),default_payment_terms text,default_incoterm text,minimum_order_value numeric check(minimum_order_value>=0),internal_rating integer check(internal_rating between 1 and 5),internal_notes text not null default '',is_preferred boolean not null default false,archived_at timestamptz,revision bigint not null default 1,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(workspace_id,id));
create table public.supplier_contacts(id uuid primary key default gen_random_uuid(),workspace_id uuid not null,owner_id uuid not null,supplier_id uuid not null,name text not null,role text,email text,phone text,preferred_contact_method text,notes text not null default '',is_primary boolean not null default false,archived_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),foreign key(workspace_id,supplier_id) references public.suppliers(workspace_id,id));
create table public.supplier_research_candidates(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),owner_id uuid not null,candidate_name text not null,candidate_type text not null,source_url text,source_title text,source_captured_at timestamptz,country_code text,currency text,candidate_summary text,claimed_capabilities text[] not null default '{}',evidence_notes text,status text not null default 'unreviewed' check(status in('unreviewed','reviewing','shortlisted','rejected','converted','archived')),reviewed_at timestamptz,converted_supplier_id uuid,rejection_reason text,revision bigint not null default 1,creation_key uuid not null default gen_random_uuid(),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(workspace_id,creation_key),foreign key(workspace_id,converted_supplier_id) references public.suppliers(workspace_id,id));
create table public.supplier_documents(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),owner_id uuid not null,supplier_id uuid not null,supplier_product_domain text check(supplier_product_domain in('raw_material','packaging')),supplier_product_id text,equipment_item_id uuid,document_type text not null,title text not null,version text not null default '1',source text,issue_date date,review_date date,status text not null default 'current' check(status in('current','superseded','removed')),verification_status text not null default 'not_reviewed',storage_object_path text,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),foreign key(workspace_id,supplier_id) references public.suppliers(workspace_id,id));
create table public.supplier_quotes(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),owner_id uuid not null,supplier_id uuid not null,quote_reference text,quote_date date not null,valid_until date,currency text not null,shipping_cost numeric,duties_estimate numeric,tax_estimate numeric,payment_fee numeric,additional_cost numeric,payment_terms text,incoterm text,lead_time_days integer,status text not null default 'draft' check(status in('draft','received','under_review','accepted_internal','declined','expired','superseded','archived')),internal_notes text not null default '',source_document_id uuid,archived_at timestamptz,revision bigint not null default 1,creation_key uuid not null default gen_random_uuid(),created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(workspace_id,id),unique(workspace_id,creation_key),foreign key(workspace_id,supplier_id) references public.suppliers(workspace_id,id),foreign key(source_document_id) references public.supplier_documents(id));
create table public.supplier_quote_lines(id uuid primary key default gen_random_uuid(),workspace_id uuid not null,owner_id uuid not null,quote_id uuid not null,supplier_product_domain text check(supplier_product_domain in('raw_material','packaging','equipment')),supplier_product_id text,equipment_item_id uuid,description text not null,quantity numeric not null check(quantity>0),unit text not null,unit_price numeric not null check(unit_price>=0),line_discount numeric not null default 0 check(line_discount>=0),line_total numeric generated always as (quantity*unit_price-line_discount) stored,moq numeric,order_multiple numeric,lead_time_days integer,notes text not null default '',display_order integer not null default 0,foreign key(workspace_id,quote_id) references public.supplier_quotes(workspace_id,id));
create table public.currency_comparison_rates(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),owner_id uuid not null,from_currency text not null,to_currency text not null,rate numeric not null check(rate>0),effective_at timestamptz not null,source_label text not null,created_at timestamptz not null default now());
create table public.stock_policies(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),owner_id uuid not null,inventory_domain text not null check(inventory_domain in('raw_material','packaging')),ingredient_id text,supplier_product_id text,packaging_component_id text,packaging_supplier_product_id text,policy_status text not null default 'draft' check(policy_status in('draft','active','paused','archived')),minimum_on_hand numeric not null check(minimum_on_hand>=0),target_on_hand numeric not null check(target_on_hand>=minimum_on_hand),safety_stock numeric,reorder_point numeric,preferred_order_quantity numeric,unit text not null,expected_lead_time_days integer,review_frequency text,is_basis_item boolean not null default false,rationale text not null default '',archived_at timestamptz,revision bigint not null default 1,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(num_nonnulls(ingredient_id,supplier_product_id,packaging_component_id,packaging_supplier_product_id)=1),check((inventory_domain='raw_material' and (ingredient_id is not null or supplier_product_id is not null)) or (inventory_domain='packaging' and (packaging_component_id is not null or packaging_supplier_product_id is not null))));
create table public.purchase_plans(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),owner_id uuid not null,title text not null,status text not null default 'draft' check(status in('draft','ready_for_review','approved_internal','ordered_external','partially_received','received','cancelled','archived')),purpose text not null default '',target_date date,supplier_id uuid,currency text,source_type text,source_id text,internal_notes text not null default '',estimated_merchandise_total numeric,estimated_landed_total numeric,approved_at timestamptz,ordered_at timestamptz,cancelled_at timestamptz,archived_at timestamptz,revision bigint not null default 1,creation_key uuid not null default gen_random_uuid(),external_order_key uuid,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(workspace_id,id),unique(workspace_id,creation_key),unique(workspace_id,external_order_key),foreign key(workspace_id,supplier_id) references public.suppliers(workspace_id,id));
create table public.purchase_plan_lines(id uuid primary key default gen_random_uuid(),workspace_id uuid not null,owner_id uuid not null,purchase_plan_id uuid not null,inventory_domain text not null check(inventory_domain in('raw_material','packaging','equipment')),supplier_product_id text,description text not null,planned_quantity numeric not null check(planned_quantity>0),unit text not null,pack_count numeric,pack_size numeric,estimated_unit_price numeric,estimated_line_total numeric,currency text,source_quote_line_id uuid,requirement_reason text,requirement_basis jsonb not null default '{}',received_quantity numeric not null default 0,display_order integer not null default 0,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),foreign key(workspace_id,purchase_plan_id) references public.purchase_plans(workspace_id,id),foreign key(source_quote_line_id) references public.supplier_quote_lines(id),check(received_quantity>=0 and received_quantity<=planned_quantity));
create table public.equipment_items(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),owner_id uuid not null,name text not null,equipment_type text not null,status text not null default 'research' check(status in('research','planned_purchase','ordered','available','in_use','cleaning_required','maintenance_required','calibration_required','out_of_service','retired','archived')),manufacturer text,model text,serial_number text,supplier_id uuid,supplier_product_id text,purchase_date date,purchase_cost numeric,purchase_currency text,warranty_until date,location text,capacity_value numeric,capacity_unit text,minimum_value numeric,maximum_value numeric,precision_value numeric,precision_unit text,power_requirement text,food_cosmetic_contact boolean,internal_notes text not null default '',archived_at timestamptz,revision bigint not null default 1,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(workspace_id,id),foreign key(workspace_id,supplier_id) references public.suppliers(workspace_id,id));
alter table public.supplier_documents add constraint supplier_documents_equipment_fk foreign key(workspace_id,equipment_item_id) references public.equipment_items(workspace_id,id);
alter table public.supplier_quote_lines add constraint quote_lines_equipment_fk foreign key(workspace_id,equipment_item_id) references public.equipment_items(workspace_id,id);
create table public.equipment_capabilities(id uuid primary key default gen_random_uuid(),workspace_id uuid not null,owner_id uuid not null,equipment_item_id uuid not null,capability_type text not null,minimum_value numeric,maximum_value numeric,precision numeric,unit text,notes text not null default '',created_at timestamptz not null default now(),foreign key(workspace_id,equipment_item_id) references public.equipment_items(workspace_id,id));
create table public.equipment_policies(id uuid primary key default gen_random_uuid(),workspace_id uuid not null,owner_id uuid not null,equipment_item_id uuid not null,status text not null default 'active' check(status in('active','paused','archived')),inspection_interval_days integer,calibration_interval_days integer,maintenance_interval_days integer,cleaning_required_before_use boolean not null default false,cleaning_required_after_use boolean not null default false,verification_notes text not null default '',revision bigint not null default 1,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),foreign key(workspace_id,equipment_item_id) references public.equipment_items(workspace_id,id));
create table public.equipment_service_events(id uuid primary key default gen_random_uuid(),workspace_id uuid not null,owner_id uuid not null,equipment_item_id uuid not null,event_type text not null check(event_type in('inspection','maintenance','repair','calibration','verification','cleaning','sanitation','decommission','other')),performed_at timestamptz not null,performed_by text,result_status text not null,notes text not null default '',next_due_at timestamptz,source_document_id uuid,supersedes_event_id uuid,created_at timestamptz not null default now(),foreign key(workspace_id,equipment_item_id) references public.equipment_items(workspace_id,id),foreign key(source_document_id) references public.supplier_documents(id),foreign key(supersedes_event_id) references public.equipment_service_events(id));
create table public.process_equipment_requirements(id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id),owner_id uuid not null,source_type text not null,source_id text not null,required_equipment_type text,required_capability text,minimum_capacity numeric,required_precision numeric,unit text,quantity_required integer not null default 1 check(quantity_required>0),requirement_level text not null check(requirement_level in('required','recommended','optional')),notes text not null default '',created_at timestamptz not null default now(),check(num_nonnulls(required_equipment_type,required_capability)=1));
alter table public.supplier_products add column supplier_id uuid,add column moq numeric,add column order_multiple numeric,add column lead_time_days integer,add column availability_status text,add column sample_available boolean,add column discontinued boolean not null default false,add column last_verified_date date,add constraint supplier_products_supplier_fk foreign key(workspace_id,supplier_id) references public.suppliers(workspace_id,id);
alter table public.packaging_supplier_products add column supplier_id uuid,add column moq numeric,add column order_multiple numeric,add column lead_time_days integer,add column availability_status text,add column sample_available boolean,add column discontinued boolean not null default false,add column last_verified_date date,add constraint packaging_supplier_products_supplier_fk foreign key(workspace_id,supplier_id) references public.suppliers(workspace_id,id);
-- The preserved v9 JSON importer expands records against the current row type,
-- so newly added fields arrive as explicit nulls rather than invoking defaults.
create function public.phase10_supplier_product_defaults() returns trigger language plpgsql set search_path=public,pg_temp as $$begin new.discontinued:=coalesce(new.discontinued,false);return new;end$$;
create trigger supplier_products_phase10_defaults before insert or update on public.supplier_products for each row execute function public.phase10_supplier_product_defaults();
create trigger packaging_supplier_products_phase10_defaults before insert or update on public.packaging_supplier_products for each row execute function public.phase10_supplier_product_defaults();
create index suppliers_library on public.suppliers(workspace_id,status,updated_at desc);create index quotes_attention on public.supplier_quotes(workspace_id,valid_until,status);create index plans_attention on public.purchase_plans(workspace_id,status,target_date);create index equipment_attention on public.equipment_items(workspace_id,status);create index service_due on public.equipment_service_events(workspace_id,next_due_at);
do $$ declare t text;begin foreach t in array array['suppliers','supplier_contacts','supplier_research_candidates','supplier_documents','supplier_quotes','supplier_quote_lines','currency_comparison_rates','stock_policies','purchase_plans','purchase_plan_lines','equipment_items','equipment_capabilities','equipment_policies','equipment_service_events','process_equipment_requirements'] loop execute format('alter table public.%I enable row level security',t);execute format('create policy owner_all on public.%I for all to authenticated using(owner_id=auth.uid()) with check(owner_id=auth.uid() and exists(select 1 from public.workspaces w where w.id=workspace_id and w.owner_id=auth.uid() and w.lifecycle_state=''active''))',t);execute format('revoke all on public.%I from anon',t);execute format('grant select,insert,update on public.%I to authenticated',t);end loop;end $$;
revoke delete on public.suppliers,public.supplier_research_candidates,public.supplier_quotes,public.supplier_quote_lines,public.purchase_plans,public.purchase_plan_lines,public.equipment_items,public.equipment_capabilities,public.equipment_policies,public.equipment_service_events,public.process_equipment_requirements from authenticated;
create or replace function public.convert_supplier_candidate(candidate_id uuid,idempotency uuid) returns uuid language plpgsql security definer set search_path=public,pg_temp as $$declare uid uuid:=auth.uid();c supplier_research_candidates;s uuid;begin if uid is null then raise exception 'Authentication required';end if;select * into c from supplier_research_candidates where id=candidate_id and owner_id=uid for update;if c.id is null then raise exception 'Candidate unavailable';end if;if c.converted_supplier_id is not null then return c.converted_supplier_id;end if;if c.status not in('reviewing','shortlisted') then raise exception 'Candidate is not eligible for conversion';end if;insert into suppliers(workspace_id,owner_id,legal_name,supplier_type,status,country_code,default_currency,internal_notes)values(c.workspace_id,uid,c.candidate_name,c.candidate_type,'candidate',c.country_code,c.currency,coalesce(c.evidence_notes,''))returning id into s;update supplier_research_candidates set status='converted',converted_supplier_id=s,reviewed_at=now(),revision=revision+1,updated_at=now() where id=c.id;return s;end$$;
revoke all on function public.convert_supplier_candidate(uuid,uuid) from public,anon;grant execute on function public.convert_supplier_candidate(uuid,uuid) to authenticated;
create or replace function public.mark_purchase_plan_external_order(plan_id uuid,idempotency uuid) returns uuid language plpgsql security definer set search_path=public,pg_temp as $$declare uid uuid:=auth.uid();p purchase_plans;begin select * into p from purchase_plans where id=plan_id and owner_id=uid for update;if p.id is null then raise exception 'Purchase Plan unavailable';end if;if p.status='ordered_external' and p.external_order_key=idempotency then return p.id;end if;if p.status<>'approved_internal' then raise exception 'Purchase Plan is not approved internally';end if;update purchase_plans set status='ordered_external',ordered_at=now(),external_order_key=idempotency,revision=revision+1,updated_at=now() where id=p.id;return p.id;end$$;
revoke all on function public.mark_purchase_plan_external_order(uuid,uuid) from public,anon;grant execute on function public.mark_purchase_plan_external_order(uuid,uuid) to authenticated;
